inline:<div id="header-root" class="c1-header">
  <div class="c1-title-container">
    <h1 class="c1-title">The DNA Archive: Digitalized Life</h1>
    <div class="c1-glow-line"></div>
  </div>
  <style>
    #header-root {
      background: #050A0C;
      padding: 3rem 2rem;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      text-align: center;
      border-bottom: 1px solid #39FF14;
    }
    .c1-title {
      font-family: 'Inter', 'Montserrat', sans-serif;
      color: #39FF14;
      font-size: clamp(2rem, 5vw, 4rem);
      letter-spacing: 0.2em;
      text-transform: uppercase;
      margin: 0;
      text-shadow: 0 0 15px #39FF14, 0 0 30px #00FFFF;
    }
    .c1-glow-line {
      height: 2px;
      width: 0%;
      background: linear-gradient(90deg, #39FF14, #00FFFF);
      margin-top: 1rem;
      transition: width 1.5s ease-out;
    }
    .c1-header.mounted .c1-glow-line {
      width: 100%;
    }
  </style>
  <script>
    window.c1_updateHeaderGlow = (intensity) => {
      const title = document.querySelector('.c1-title');
      if (title) title.style.textShadow = `0 0 ${15 * intensity}px #39FF14, 0 0 ${30 * intensity}px #00FFFF`;
    };
    window.c1_mount = () => {
      const root = document.getElementById('header-root');
      if (!window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
        root.classList.add('mounted');
      }
    };
    window.c1_destroy = () => {};
  </script>
</div>
